using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _sut;

        public NotificationServiceTests()
        {
            _sut = new NotificationService();
            // Drain the static queue to isolate tests
            while (_sut.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _sut.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            // Act
            _sut.SendNotification("Course", "101", EntityOperation.UPDATE, "Teacher");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 101", notification.Message);
        }

        [Fact]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Department", "5", EntityOperation.DELETE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "has been created")]
        [InlineData(EntityOperation.UPDATE, "has been updated")]
        [InlineData(EntityOperation.DELETE, "has been deleted")]
        public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedFragment)
        {
            // Act
            _sut.SendNotification("Student", "1", "Test Student", operation);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains(expectedFragment, notification.Message);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_MultipleMessages_ReturnsFifoOrder()
        {
            // Arrange
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            // Act & Assert
            Assert.Equal("A", _sut.ReceiveNotification()!.EntityType);
            Assert.Equal("B", _sut.ReceiveNotification()!.EntityType);
            Assert.Equal("C", _sut.ReceiveNotification()!.EntityType);
            Assert.Null(_sut.ReceiveNotification());
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            // Arrange
            var before = DateTime.Now;

            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.True(notification.CreatedAt >= before);
            Assert.True(notification.CreatedAt <= DateTime.Now);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert (no-op implementation should not throw)
            var exception = Record.Exception(() => _sut.MarkAsRead(42));
            Assert.Null(exception);
        }
    }
}

using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(1, result.First());
            Assert.Equal(10, result.Last());
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

            // Assert
            Assert.Equal(5, result.Count);
            Assert.Equal(3, result.PageIndex);
            Assert.Equal(21, result.First());
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

            // Assert
            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

            // Assert
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_ExactPageSize_SinglePage()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Constructor_CalculatesTotalPagesCorrectly()
        {
            // 11 items with page size 5 = 3 pages (ceil(11/5))
            var items = Enumerable.Range(1, 5).ToList();
            var result = new PaginatedList<int>(items, count: 11, pageIndex: 1, pageSize: 5);

            Assert.Equal(3, result.TotalPages);
        }
    }
}

