using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(1, result.First());
            Assert.Equal(10, result.Last());
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

            // Assert
            Assert.Equal(5, result.Count);
            Assert.Equal(3, result.PageIndex);
            Assert.Equal(21, result.First());
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

            // Assert
            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

            // Assert
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_ExactPageSize_SinglePage()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Constructor_CalculatesTotalPagesCorrectly()
        {
            // 11 items with page size 5 = 3 pages (ceil(11/5))
            var items = Enumerable.Range(1, 5).ToList();
            var result = new PaginatedList<int>(items, count: 11, pageIndex: 1, pageSize: 5);

            Assert.Equal(3, result.TotalPages);
        }
    }
}

