        public void FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
        {
            // Arrange
            var student = new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = DateTime.Now
            };

            // Act & Assert
            Assert.Equal(expected, student.FullName);
        }
    }

    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            // Assert
            Assert.True(typeof(Student).IsSubclassOf(typeof(Person)));
        }

        [Fact]
        public void Student_HasEnrollmentsCollection()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.Now,
                Enrollments = new List<Enrollment>()
            };

            // Assert
            Assert.NotNull(student.Enrollments);
            Assert.Empty(student.Enrollments);
        }
    }

    public class InstructorTests
    {
        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            Assert.True(typeof(Instructor).IsSubclassOf(typeof(Person)));
        }

        [Fact]
        public void Instructor_HasCourseAssignmentsAndOfficeAssignment()
        {
            // Arrange
            var instructor = new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 1" }
            };

            // Assert
            Assert.NotNull(instructor.CourseAssignments);
            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Room 1", instructor.OfficeAssignment.Location);
        }
    }

    public class CourseTests
    {
        [Fact]
        public void Course_PropertiesSetCorrectly()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/uploads/chem.png"
            };

            // Assert
            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/uploads/chem.png", course.TeachingMaterialImagePath);
        }
    }

    public class DepartmentTests
    {
        [Fact]
        public void Department_PropertiesSetCorrectly()
        {
            // Arrange
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000.00m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

            // Assert
            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000.00m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorIdCanBeNull()
        {
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Now };
            Assert.Null(dept.InstructorID);
        }
    }

    public class EnrollmentTests
    {
        [Fact]
        public void Enrollment_GradeCanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 1,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Enrollment_GradeValues_AreValid(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }
    }

    public class NotificationModelTests
    {
        [Fact]
        public void Notification_PropertiesSetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }
    }
}

