        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NonExistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            var instructor = CreateTestInstructor("ToDelete", "Person");
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            // Act
            var result = _controller.Delete(instructor.ID) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("ToDelete", model.LastName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
        {
            // Arrange
            var instructor = CreateTestInstructor("Removable", "Test");
            instructor.OfficeAssignment = new OfficeAssignment { Location = "Room 200" };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            // Act
            var result = _controller.DeleteConfirmed(instructor.ID);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Instructors.Find(instructor.ID));
        }

        [Fact]
        public void DeleteConfirmed_InstructorIsDeptAdmin_NullsOutDepartmentReference()
        {
            // Arrange
            var instructor = CreateTestInstructor("Admin", "Dept");
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var dept = new Department
            {
                Name = "Managed",
                Budget = 50000m,
                StartDate = DateTime.Now,
                InstructorID = instructor.ID
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            instructor.OfficeAssignment = new OfficeAssignment { InstructorID = instructor.ID, Location = "Office" };
            _context.SaveChanges();

            // Act
            _controller.DeleteConfirmed(instructor.ID);

            // Assert
            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept!.InstructorID);
        }

        #endregion
