using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Student CreateTestStudent(string lastName = "Smith", string firstName = "John", DateTime? enrollmentDate = null)
        {
            return new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
            };
        }

        private void SeedStudents()
        {
            _context.Students.AddRange(
                CreateTestStudent("Adams", "Alice", new DateTime(2023, 1, 15)),
                CreateTestStudent("Brown", "Bob", new DateTime(2023, 3, 20)),
                CreateTestStudent("Clark", "Charlie", new DateTime(2022, 9, 1)),
                CreateTestStudent("Davis", "Diana", new DateTime(2023, 1, 15))
            );
            _context.SaveChanges();
        }

        #region Index Tests

        [Fact]
        public void Index_NoParameters_ReturnsViewWithStudentsOrderedByLastName()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(4, model.Count);
            Assert.Equal("Adams", model.First().LastName);
        }

        [Fact]
        public void Index_NameDescSort_ReturnsStudentsDescending()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Davis", model.First().LastName);
        }

        [Fact]
        public void Index_DateSort_ReturnsStudentsByEnrollmentDateAsc()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Clark", model.First().LastName); // 2022-09-01
        }

        [Fact]
        public void Index_DateDescSort_ReturnsStudentsByEnrollmentDateDesc()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Brown", model.First().LastName); // 2023-03-20
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, "Adams", null) as ViewResult;

            // Assert
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Adams", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            // Assert
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Alice", model.First().FirstMidName);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPageToOne()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, null, "test", 5) as ViewResult;

            // Assert - when searchString != null, page is reset to 1
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index(null, "Adams", null, null) as ViewResult;

            // Assert
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            // Arrange
            SeedStudents();

            // Act
            var result = _controller.Index("Date", null, "test", null) as ViewResult;

            // Assert
            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var student = CreateTestStudent();
            _context.Students.Add(student);
            _context.SaveChanges();

            // Act
            var result = _controller.Details(student.ID) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Smith", model.LastName);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = CreateTestStudent();

            // Act
            var result = _controller.Create(student);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavesStudentToDatabase()
        {
            // Arrange
            var student = CreateTestStudent("TestLast", "TestFirst");

            // Act
            _controller.Create(student);

            // Assert
            Assert.Single(_context.Students);
            var saved = _context.Students.First();
            Assert.Equal("TestLast", saved.LastName);
            Assert.Equal("TestFirst", saved.FirstMidName);
        }

        [Fact]
        public void Create_Post_DefaultEnrollmentDate_AddsModelError()
        {
            // Arrange
            var student = CreateTestStudent();
            student.EnrollmentDate = DateTime.MinValue;

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var student = CreateTestStudent();
            _controller.ModelState.AddModelError("LastName", "Required");

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit((int?)null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NonExistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var student = CreateTestStudent();
            _context.Students.Add(student);
            _context.SaveChanges();

            // Act
            var result = _controller.Edit(student.ID) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = CreateTestStudent();
            _context.Students.Add(student);
            _context.SaveChanges();
            _context.Entry(student).State = EntityState.Detached;

            student.LastName = "UpdatedName";

            // Act
            var result = _controller.Edit(student);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_DefaultEnrollmentDate_AddsModelError()
        {
            // Arrange
