using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;
        private readonly string _tempPath;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();
            _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempPath);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempPath);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempPath);

            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempPath))
            {
                Directory.Delete(_tempPath, recursive: true);
            }
        }

        private Department CreateTestDepartment()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 100000m,
                StartDate = new DateTime(2023, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        private Course CreateTestCourse(int courseId = 1001, string title = "Intro to CS", int credits = 3, int? departmentId = null)
        {
            if (departmentId == null)
            {
                var dept = CreateTestDepartment();
                departmentId = dept.DepartmentID;
            }
            return new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = credits,
                DepartmentID = departmentId.Value
            };
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            // Arrange
            var dept = CreateTestDepartment();
            _context.Courses.AddRange(
                new Course { CourseID = 1001, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID },
                new Course { CourseID = 1002, Title = "Physics", Credits = 3, DepartmentID = dept.DepartmentID }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<IList<Course>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            // Arrange
            var course = CreateTestCourse();
            _context.Courses.Add(course);
            _context.SaveChanges();

            // Act
            var result = _controller.Details(course.CourseID) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Intro to CS", model.Title);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            // Arrange
            CreateTestDepartment();

            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            // Arrange
            var course = CreateTestCourse();

            // Act
            var result = _controller.Create(course, null);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_NoImage_SavesToDB()
        {
            // Arrange
            var course = CreateTestCourse(2001, "Algorithms");

            // Act
            _controller.Create(course, null);

            // Assert
            var saved = _context.Courses.Find(2001);
            Assert.NotNull(saved);
            Assert.Equal("Algorithms", saved.Title);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            // Arrange
            var course = CreateTestCourse();
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.exe");
            fileMock.Setup(f => f.Length).Returns(1000);

            // Act
            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            // Arrange
            var course = CreateTestCourse();
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

            // Act
            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_ValidImage_UploadsAndSaves()
        {
            // Arrange
            var course = CreateTestCourse(3001, "Art History");
            var content = new byte[] { 1, 2, 3 };
            var stream = new MemoryStream(content);
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("photo.png");
            fileMock.Setup(f => f.Length).Returns(content.Length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));

            // Act
            var result = _controller.Create(course, fileMock.Object);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            var saved = _context.Courses.Find(3001);
            Assert.NotNull(saved!.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var course = CreateTestCourse();
            _controller.ModelState.AddModelError("Title", "Required");

            // Act
            var result = _controller.Create(course, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
        }

        [Theory]
        [InlineData(".jpg")]
        [InlineData(".jpeg")]
        [InlineData(".png")]
        [InlineData(".gif")]
        [InlineData(".bmp")]
        public void Create_Post_AllowedImageExtensions_Succeeds(string extension)
        {
            // Arrange
            var course = CreateTestCourse(4000 + extension.GetHashCode() % 1000, "Test Course");
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns($"photo{extension}");
            fileMock.Setup(f => f.Length).Returns(100);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            // Act
            var result = _controller.Create(course, fileMock.Object);

            // Assert
            Assert.IsType<RedirectToActionResult>(result);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit((int?)null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NonExistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit(9999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            // Arrange
            var course = CreateTestCourse(5001, "Data Structures");
            _context.Courses.Add(course);
            _context.SaveChanges();

            // Act
            var result = _controller.Edit(5001) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Data Structures", model.Title);
        }

        [Fact]
        public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            // Arrange
            var course = CreateTestCourse(6001, "Databases");
            _context.Courses.Add(course);
            _context.SaveChanges();
            _context.Entry(course).State = EntityState.Detached;

            course.Title = "Advanced Databases";

            // Act
            var result = _controller.Edit(course, null);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            // Arrange
            var course = CreateTestCourse(7001);
            _context.Courses.Add(course);
            _context.SaveChanges();
            _context.Entry(course).State = EntityState.Detached;

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.pdf");
            fileMock.Setup(f => f.Length).Returns(1000);

            // Act
            var result = _controller.Edit(course, fileMock.Object) as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            // Arrange
            var course = CreateTestCourse(8001, "To Delete");
            _context.Courses.Add(course);
            _context.SaveChanges();

            // Act
            var result = _controller.Delete(8001) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("To Delete", model.Title);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            // Arrange
            var course = CreateTestCourse(9001, "Remove Me");
            _context.Courses.Add(course);
            _context.SaveChanges();

            // Act
            var result = _controller.DeleteConfirmed(9001);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Courses.Find(9001));
        }

        [Fact]
        public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
        {
            // Arrange
            var uploadsDir = Path.Combine(_tempPath, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imagePath = Path.Combine(uploadsDir, "test.png");
            File.WriteAllText(imagePath, "fake image");

            var course = CreateTestCourse(9002, "With Image");
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.png";
            _context.Courses.Add(course);
            _context.SaveChanges();

            // Act
            _controller.DeleteConfirmed(9002);

            // Assert
            Assert.False(File.Exists(imagePath));
        }

        #endregion
    }
}

