using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new InstructorsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor CreateTestInstructor(string lastName = "Doe", string firstName = "Jane", DateTime? hireDate = null)
        {
            return new Instructor
            {
                LastName = lastName,
                FirstMidName = firstName,
                HireDate = hireDate ?? new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
        }

        private void SeedInstructorsWithCourses()
        {
            var dept = new Department
            {
                Name = "CS",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course1 = new Course { CourseID = 101, Title = "Intro CS", Credits = 3, DepartmentID = dept.DepartmentID, Enrollments = new List<Enrollment>() };
            var course2 = new Course { CourseID = 102, Title = "Algorithms", Credits = 4, DepartmentID = dept.DepartmentID, Enrollments = new List<Enrollment>() };
            _context.Courses.AddRange(course1, course2);
            _context.SaveChanges();

            var instructor = CreateTestInstructor("Smith", "Alice");
            instructor.OfficeAssignment = new OfficeAssignment { Location = "Room 101" };
            instructor.CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 101 },
                new CourseAssignment { CourseID = 102 }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
        }

        #region Index Tests

        [Fact]
        public void Index_NoParameters_ReturnsViewWithInstructors()
        {
            // Arrange
            SeedInstructorsWithCourses();

            // Act
            var result = _controller.Index(null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.Single(model.Instructors);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            // Arrange
            SeedInstructorsWithCourses();
            var instructorId = _context.Instructors.First().ID;

            // Act
            var result = _controller.Index(instructorId, null) as ViewResult;

            // Assert
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result!.Model);
            Assert.Equal(2, model.Courses.Count());
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            // Arrange
            SeedInstructorsWithCourses();
            var instructorId = _context.Instructors.First().ID;

            // Act
            var result = _controller.Index(instructorId, 101) as ViewResult;

            // Assert
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result!.Model);
            Assert.NotNull(model.Enrollments);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NonExistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Details(999);

            // Assert
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            var instructor = CreateTestInstructor("Wilson", "James");
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            // Act
            var result = _controller.Details(instructor.ID) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Wilson", model.LastName);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithAssignedCourseData()
        {
            // Arrange
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            _context.Courses.Add(new Course { CourseID = 201, Title = "TestCourse", Credits = 3, DepartmentID = dept.DepartmentID });
            _context.SaveChanges();

            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            // Arrange
            var instructor = CreateTestInstructor("NewInstructor", "Test");

            // Act
            var result = _controller.Create(instructor, null);

            // Assert
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            // Arrange
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            _context.Courses.Add(new Course { CourseID = 301, Title = "Course1", Credits = 3, DepartmentID = dept.DepartmentID });
            _context.SaveChanges();

            var instructor = CreateTestInstructor("CourseInstructor", "With");

            // Act
            var result = _controller.Create(instructor, new[] { "301" });

