using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;
        private readonly NotificationService _notificationService;

        public NotificationsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
            _notificationService = new NotificationService();
            // Drain the queue for test isolation
            while (_notificationService.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            _notificationService.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccess()
        {
            // Drain any existing notifications
            while (true)
            {
                var result = _controller.GetNotifications();
                var json = result.Value as dynamic;
                break;
            }

            // Act
            var actionResult = _controller.GetNotifications();

            // Assert
            Assert.NotNull(actionResult);
            Assert.IsType<JsonResult>(actionResult);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange - send notifications via the service
            _notificationService.SendNotification("Student", "1", "John", EntityOperation.CREATE, "Admin");

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccessJson()
        {
            // Act
            var result = _controller.MarkAsRead(1);

            // Assert
            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void Index_ReturnsView()
        {
            // Act
            var result = _controller.Index();

            // Assert
            Assert.IsType<ViewResult>(result);
        }
    }
}

